function ExpenseTracker({ expenses, properties }) {
  const { div, h1, h2, span, table, thead, tbody, tr, th, td } = tags;
  const [showAddForm, setShowAddForm] = createSignal(false);
  const [propertyFilter, setPropertyFilter] = createSignal('all');
  const [categoryFilter, setCategoryFilter] = createSignal('all');
  const [dateFrom, setDateFrom] = createSignal('');
  const [dateTo, setDateTo] = createSignal('');

  const categories = ['Mortgage', 'Insurance', 'Property Taxes', 'Utilities', 'Maintenance', 'Management', 'HOA', 'Legal', 'Marketing', 'Other'];

  const filtered = () => expenses.filter(e => {
    if (propertyFilter() !== 'all' && e.propertyId !== propertyFilter()) return false;
    if (categoryFilter() !== 'all' && e.category !== categoryFilter()) return false;
    if (dateFrom() && new Date(e.date) < new Date(dateFrom())) return false;
    if (dateTo() && new Date(e.date) > new Date(dateTo())) return false;
    return true;
  });

  const totalExpenses = filtered().reduce((sum, e) => sum + e.amount, 0);
  const byCategory = categories.map(cat => ({
    name: cat,
    amount: filtered().filter(e => e.category === cat).reduce((sum, e) => sum + e.amount, 0)
  })).filter(c => c.amount > 0).sort((a, b) => b.amount - a.amount);

  return div({ class: css('_flex _col _gap6') },
    div({ class: css('_flex _jcsb _aic') },
      h1({ class: css('_heading3') }, 'Expenses'),
      div({ class: css('_flex _gap2') },
        Button({ variant: 'outline' }, icon('download'), 'Export'),
        Button({ variant: 'primary', onclick: () => setShowAddForm(true) }, icon('plus'), 'Add Expense')
      )
    ),
    div({ class: css('_flex _gap4 _aic _flexwrap') },
      div({ class: css('_flex _gap2 _aic') },
        span({ class: css('_textsm _fgmuted') }, 'From'),
        Input({ type: 'date', value: dateFrom(), oninput: e => setDateFrom(e.target.value) }),
        span({ class: css('_textsm _fgmuted') }, 'To'),
        Input({ type: 'date', value: dateTo(), oninput: e => setDateTo(e.target.value) })
      ),
      Select({ value: propertyFilter(), onchange: e => setPropertyFilter(e.target.value) },
        tags.option({ value: 'all' }, 'All Properties'),
        ...properties.map(p => tags.option({ value: p.id }, p.name))
      ),
      Select({ value: categoryFilter(), onchange: e => setCategoryFilter(e.target.value) },
        tags.option({ value: 'all' }, 'All Categories'),
        ...categories.map(c => tags.option({ value: c }, c))
      ),
      span({ class: css('_ml[auto] _font500') }, `Total: $${totalExpenses.toLocaleString()}`)
    ),
    byCategory.length > 0 ? div({ class: css('_grid _cols4 _gap4') },
      ...byCategory.slice(0, 4).map(cat =>
        div({ class: css('estate-card _p4') },
          span({ class: css('_heading4 _block') }, `$${cat.amount.toLocaleString()}`),
          span({ class: css('_textsm _fgmuted') }, cat.name)
        )
      )
    ) : null,
    div({ class: css('estate-table _overflow[auto]') },
      table({ class: css('_wfull') },
        thead({},
          tr({ class: css('_bgSurface') },
            th({ class: css('_p3 _textleft _font500') }, 'Date'),
            th({ class: css('_p3 _textleft _font500') }, 'Property'),
            th({ class: css('_p3 _textleft _font500') }, 'Category'),
            th({ class: css('_p3 _textleft _font500') }, 'Description'),
            th({ class: css('_p3 _textleft _font500') }, 'Vendor'),
            th({ class: css('_p3 _tr _font500') }, 'Amount'),
            th({ class: css('_p3 _tc _font500') }, 'Receipt'),
            th({ class: css('_p3') })
          )
        ),
        tbody({},
          ...filtered().map((e, i) =>
            tr({ class: css(i % 2 === 0 ? '' : '_bgSurfaceRaised') },
              td({ class: css('_p3 _textsm') }, new Date(e.date).toLocaleDateString()),
              td({ class: css('_p3 _textsm') }, e.propertyName),
              td({ class: css('_p3') }, Badge({ variant: 'outline' }, e.category)),
              td({ class: css('_p3 _textsm _maxw[200px] _truncate') }, e.description),
              td({ class: css('_p3 _textsm') }, e.vendor || '—'),
              td({ class: css('_p3 _tr _font500') }, `$${e.amount.toLocaleString()}`),
              td({ class: css('_p3 _tc') },
                e.receipt ? Button({ variant: 'ghost', size: 'sm' }, icon('paperclip', { size: '14' })) : span({ class: css('_fgmuted') }, '—')
              ),
              td({ class: css('_p3') },
                div({ class: css('_flex _gap1') },
                  Button({ variant: 'ghost', size: 'sm' }, icon('edit', { size: '14' })),
                  Button({ variant: 'ghost', size: 'sm' }, icon('trash', { size: '14' }))
                )
              )
            )
          )
        )
      )
    )
  );
}

