function AddExpenseForm({ properties, onSave, onCancel }) {
  const { div, form, h2, label } = tags;
  const [formData, setFormData] = createSignal({ date: new Date().toISOString().split('T')[0], propertyId: '', category: '', description: '', amount: '', vendor: '', receipt: null });
  const categories = ['Mortgage', 'Insurance', 'Property Taxes', 'Utilities', 'Maintenance', 'Management', 'HOA', 'Legal', 'Marketing', 'Other'];

  return div({ class: css('estate-card _p6') },
    h2({ class: css('_heading4 _mb6') }, 'Add Expense'),
    form({ class: css('_flex _col _gap4'), onsubmit: e => { e.preventDefault(); onSave(formData()); } },
      div({ class: css('_grid _cols2 _gap4') },
        div({},
          label({ class: css('_textsm _font500 _mb1 _block') }, 'Date'),
          Input({ type: 'date', value: formData().date, oninput: e => setFormData({ ...formData(), date: e.target.value }), required: true })
        ),
        div({},
          label({ class: css('_textsm _font500 _mb1 _block') }, 'Property'),
          Select({ value: formData().propertyId, onchange: e => setFormData({ ...formData(), propertyId: e.target.value }), required: true },
            tags.option({ value: '' }, 'Select property...'),
            ...properties.map(p => tags.option({ value: p.id }, p.name))
          )
        ),
        div({},
          label({ class: css('_textsm _font500 _mb1 _block') }, 'Category'),
          Select({ value: formData().category, onchange: e => setFormData({ ...formData(), category: e.target.value }), required: true },
            tags.option({ value: '' }, 'Select category...'),
            ...categories.map(c => tags.option({ value: c }, c))
          )
        ),
        div({},
          label({ class: css('_textsm _font500 _mb1 _block') }, 'Amount'),
          Input({ type: 'number', step: '0.01', value: formData().amount, oninput: e => setFormData({ ...formData(), amount: e.target.value }), required: true, placeholder: '0.00' })
        ),
        div({ class: css('_col[span-2]') },
          label({ class: css('_textsm _font500 _mb1 _block') }, 'Description'),
          Textarea({ value: formData().description, oninput: e => setFormData({ ...formData(), description: e.target.value }), rows: 2 })
        ),
        div({},
          label({ class: css('_textsm _font500 _mb1 _block') }, 'Vendor'),
          Input({ value: formData().vendor, oninput: e => setFormData({ ...formData(), vendor: e.target.value }) })
        ),
        div({},
          label({ class: css('_textsm _font500 _mb1 _block') }, 'Receipt'),
          Input({ type: 'file', accept: 'image/*,application/pdf', onchange: e => setFormData({ ...formData(), receipt: e.target.files[0] }) })
        )
      ),
      div({ class: css('_flex _jce _gap2 _pt4 _borderT') },
        Button({ type: 'button', variant: 'outline', onclick: onCancel }, 'Cancel'),
        Button({ type: 'submit', variant: 'primary' }, 'Add Expense')
      )
    )
  );
}

